 88→impl TriageState {
 89→    pub fn new(param_names: Vec<String>) -> Self {
 90→        Self {
 91→            traces: Vec::new(),
 92→            trace_keys: HashSet::new(),
 93→            observed_directions: HashSet::new(),
 94→            param_names,
 95→            total_verdicts: 0,
 96→            skip_verdicts: 0,
 97→            samples_taken: 0,
 98→            mispredictions: 0,
 99→            disable_reason: None,
100→        }
