 1→//! Byte-level fuzz targets for deserialization boundaries.
 2→//!
 3→//! Feeds arbitrary byte vectors to every `serde_json::from_slice` and
 4→//! `serde_yaml::from_slice` entry point in shatter-core. The only assertion is
 5→//! "does not panic" — a returned `Err` is fine; an unwinding panic is a bug.
 6→//!
 7→//! These use proptest (not cargo-fuzz) so they run in CI without nightly.
 8→//! For deeper coverage-guided fuzzing, consider adding cargo-fuzz targets later.
 9→
10→use proptest::prelude::*;
11→
12→use shatter_core::config::ShatterConfig;
13→use shatter_core::protocol::{Request, Response};
14→use shatter_core::spec::FunctionSpec;
15→use shatter_core::sym_expr::SymExpr;
16→use shatter_core::types::TypeInfo;
17→
18→const FUZZ_CASES: u32 = 1000;
19→const MAX_INPUT_LEN: usize = 1024;
20→
21→fn fuzz_config() -> ProptestConfig {
22→    ProptestConfig {
23→        cases: FUZZ_CASES,
24→        ..ProptestConfig::default()
25→    }
26→}
27→
28→proptest! {
29→    #![proptest_config(fuzz_config())]
30→
31→    /// Arbitrary bytes fed to `Request` JSON deserialization must not panic.
32→    #[test]
33→    fn fuzz_request_json(bytes in prop::collection::vec(any::<u8>(), 0..MAX_INPUT_LEN)) {
34→        let _ = serde_json::from_slice::<Request>(&bytes);
35→    }
36→
37→    /// Arbitrary bytes fed to `Response` JSON deserialization must not panic.
38→    #[test]
39→    fn fuzz_response_json(bytes in prop::collection::vec(any::<u8>(), 0..MAX_INPUT_LEN)) {
40→        let _ = serde_json::from_slice::<Response>(&bytes);
41→    }
42→
43→    /// Arbitrary bytes fed to `SymExpr` JSON deserialization must not panic.
44→    #[test]
45→    fn fuzz_symexpr_json(bytes in prop::collection::vec(any::<u8>(), 0..MAX_INPUT_LEN)) {
46→        let _ = serde_json::from_slice::<SymExpr>(&bytes);
47→    }
48→
49→    /// Arbitrary bytes fed to `TypeInfo` JSON deserialization must not panic.
50→    #[test]
51→    fn fuzz_typeinfo_json(bytes in prop::collection::vec(any::<u8>(), 0..MAX_INPUT_LEN)) {
52→        let _ = serde_json::from_slice::<TypeInfo>(&bytes);
53→    }
54→
55→    /// Arbitrary bytes fed to `FunctionSpec` YAML deserialization must not panic.
56→    #[test]
57→    fn fuzz_function_spec_yaml(bytes in prop::collection::vec(any::<u8>(), 0..MAX_INPUT_LEN)) {
58→        let _ = serde_yaml::from_slice::<FunctionSpec>(&bytes);
59→    }
